CREATE CACHED TABLE IF NOT EXISTS "SCRIPTS_RUN_STEP_WEB_ELEMENT" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "RUNSTEPID" BIGINT NOT NULL,
    "CREATETIMESTAMP" TIMESTAMP NULL,
    "ORDINAL" INT NOT NULL,
    "FORMINDEX" INT NULL,
    "TAGNAME" VARCHAR(1024) NULL,
    "ATTRIBUTETYPE" VARCHAR(1024) NULL,
    "ATTRIBUTEID" VARCHAR(1024) NULL,
    "ATTRIBUTENAME" VARCHAR(1024) NULL,
    "ATTRIBUTEVALUE" VARCHAR(1024) NULL,
    "TEXT" VARCHAR(4096) NULL,
    "DISPLAYED" BOOLEAN NOT NULL,
    "ENABLED" BOOLEAN NOT NULL,
    "SELECTORTYPE" VARCHAR(32) NULL,
    "SELECTORVALUE" VARCHAR(4096) NULL,
    CONSTRAINT "SCRIPTS_RUN_STEP_WEB_ELEMENT_FK_STEP"
        FOREIGN KEY ("RUNSTEPID") REFERENCES "SCRIPTS_RUN_STEP" ("ID")
);
